BEGIN
 // Network Security Model - Basic Communication

 FUNCTION sendSecureMessage(message, encryptionKey):
 // Step 1: Sender prepares message
 plaintext = message

 // Step 2: Encryption at sender side
 ciphertext = ENCRYPT(plaintext, encryptionKey)

 // Step 3: Transmit through channel (potentially insecure)
 transmittedData = sendThroughChannel(ciphertext)

 RETURN transmittedData

 FUNCTION receiveSecureMessage(transmittedData, decryptionKey):
 // Step 4: Receive encrypted data
 ciphertext = receiveFromChannel(transmittedData)

 // Step 5: Decryption at receiver side
 plaintext = DECRYPT(ciphertext, decryptionKey)

 RETURN plaintext

 // Main execution
 originalMessage = "Sensitive Data"
 sharedKey = generateKey()

 // Sender side
 encryptedData = sendSecureMessage(originalMessage, sharedKey)

 // Adversary tries to intercept
 interceptedData = adversaryIntercepts(encryptedData)

 // Receiver side
 receivedMessage = receiveSecureMessage(encryptedData, sharedKey)

 IF receivedMessage == originalMessage:
 PRINT "Secure transmission successful"
 ELSE:
 PRINT "Transmission failed"
END
